import json, pathlib, uuid
from contextlib import contextmanager

SESSION_DIR = pathlib.Path("memory/sessions")
SESSION_DIR.mkdir(parents=True, exist_ok=True)

def new_session(user_id: str) -> SessionRecord:
    return SessionRecord(
        session_id=str(uuid.uuid4()),
        user_id=user_id,
        started_at=datetime.utcnow().isoformat(),
    )

def save_session(record: SessionRecord) -> None:
    path = SESSION_DIR / f"{record.user_id}" 
    path.mkdir(parents=True, exist_ok=True)
    (path / f"{record.session_id}.json").write_text(
        json.dumps(record.__dict__, indent=2)
    )

def load_recent_sessions(
    user_id: str,
    limit: int = 5,
) -> list[SessionRecord]:
    user_dir = SESSION_DIR / user_id
    if not user_dir.exists():
        return []
    files = sorted(user_dir.glob("*.json"), key=lambda p: p.stat().st_mtime, reverse=True)
    records = []
    for f in files[:limit]:
        data = json.loads(f.read_text())
        records.append(SessionRecord(**data))
    return records

def relevant_sessions(
    user_id: str,
    current_message: str,
    limit: int = 3,
) -> list[SessionRecord]:
    """Return sessions whose topics overlap with the current message keywords."""
    all_sessions = load_recent_sessions(user_id, limit=20)
    if not all_sessions:
        return []

    msg_words = set(current_message.lower().split())

    def overlap_score(record: SessionRecord) -> int:
        topic_words = set(" ".join(record.topics).lower().split("-"))
        return len(msg_words & topic_words)

    scored = sorted(all_sessions, key=overlap_score, reverse=True)
    # Always include the most recent session regardless of topic match
    result = [scored[0]] if scored else []
    for r in scored[1:]:
        if len(result) >= limit:
            break
        if overlap_score(r) > 0:
            result.append(r)
    return result

import threading

SESSION_TIMEOUT_SECONDS = 30 * 60  # 30 minutes

class SessionManager:
    def __init__(self) -> None:
        self._sessions:  dict[str, SessionRecord] = {}
        self._histories: dict[str, list[dict]]    = {}
        self._timers:    dict[str, threading.Timer] = {}

    def get_or_create(self, user_id: str) -> SessionRecord:
        if user_id not in self._sessions:
            self._sessions[user_id]  = new_session(user_id)
            self._histories[user_id] = []
        self._reset_timer(user_id)
        return self._sessions[user_id]

    def record_turn(self, user_id: str, user_msg: str, agent_reply: str) -> None:
        history = self._histories.setdefault(user_id, [])
        history.append({"role": "user",      "content": user_msg})
        history.append({"role": "assistant", "content": agent_reply})
        self._sessions[user_id].turn_count += 1
        self._reset_timer(user_id)

    def close(self, user_id: str) -> SessionRecord | None:
        session = self._sessions.pop(user_id, None)
        history = self._histories.pop(user_id, [])
        if t := self._timers.pop(user_id, None):
            t.cancel()
        if session:
            return end_session(session, history)
        return None

    def _reset_timer(self, user_id: str) -> None:
        if t := self._timers.pop(user_id, None):
            t.cancel()
        timer = threading.Timer(SESSION_TIMEOUT_SECONDS, self.close, args=(user_id,))
        timer.daemon = True
        timer.start()
        self._timers[user_id] = timer
